<template>
    <div>
      <el-card>
        <el-form size="mini" :inline="true" @keyup.enter.native="searchList()">
          <el-form-item label="">
            <el-input disabled v-model="userInfo.name" placeholder="请输入标题" style="width: 200px"></el-input>
          </el-form-item>
          <el-form-item>
            <el-button size="mini" type="primary" @click="searchList">查询</el-button>
          </el-form-item>
        </el-form>
      </el-card>
      <el-card>
        <el-table size="mini" border :data="tableData" style="width: 100%" v-loading="listLoading">
          <el-table-column type="index" label="序号"/>
          <el-table-column label="卡号" prop="idcard" sortable width="80" />
          <el-table-column label="加密密码" prop="password"/>
        </el-table>
      </el-card>
      <el-pagination :current-page="currentPage" style="margin-top: 20px;" layout="total, prev, pager, next, jumper" :page-size="pageSize" :total="total" @current-change="currentChange"></el-pagination>  
    </div>
  </template>
  
  <script>
    import {
        adminUser, // 用户查询
  } from '@/api/index'
  
    export default {
      data() {
        return {
          userInfo: {
            user: {},
          }, // 个人信息
          searchTableData: [],
          tableData: [],
          listLoading: false,
          total: 0,
          currentPage: 1,
          pageSize: 5
        }
      },
      mounted(){
        this.userInfo = JSON.parse(window.localStorage.getItem('userInfo'))
        this.searchList();
      },
      methods: {
        // 时间格式转化
        GMTToStr(timestamp, type = 1){    
          let date = new Date(timestamp); //时间戳为10位需*1000，时间戳为13位的话不需乘1000
          let Y = date.getFullYear() + '-';
          let M = (date.getMonth() + 1) < 10 ? '0' + (date.getMonth() + 1) + '-' : (date.getMonth() + 1) + '-';
          let D = (date.getDate() < 10 ? '0' + date.getDate() : date.getDate()) + ' ';
          let H = (date.getHours() < 10 ? '0' + date.getHours() : date.getHours()) + ':'
          let Min = (date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes())
          let S = ':' + (date.getSeconds() < 10 ? '0' + date.getSeconds() : date.getSeconds())
          if (timestamp) {
            return type ? (Y + M + D + H + Min + S) : (Y + M + D)
          } else {
            return '-'
          }
  
        },
          // 分页
        currentChange(currentPage){
          this.currentPage = currentPage        
          let start = (currentPage - 1) * this.pageSize
          let end = currentPage * this.pageSize
          this.tableData = this.searchTableData.slice(start, end)
        },
        // 获取租客列表
        async searchList(){
          this.currentPage = 1
          this.listLoading = true
          let res = await adminUser({});
          this.listLoading = false
          this.total = res.results.length
          this.searchTableData = res.results
          this.tableData = this.searchTableData.slice((this.currentPage - 1) * this.pageSize ,this.pageSize*this.currentPage)
        },
      }
    }
  </script>
  
  <style scoped>
    .el-table{
      margin: 20px auto 50px;
    }
    .demo-table-expand {
      font-size: 0;
    }
    .demo-table-expand label {
      width: 90px;
      color: #99a9bf;
    }
    .demo-table-expand .el-form-item {
      margin-right: 0;
      margin-bottom: 0;
      width: 50%;
    }
    .el-pagination{
      text-align: center;
    }
    /deep/.el-card{
      margin-top: 10px;
    }
  </style>
  
  


